                        TweenService:Create(
                            successCircle,
                            TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.InOut, -1, true),
                            {Size = UDim2.new(0, 92, 0, 92)}
                        ):Play()
                    end
                    
                    if loadingText then
